extra.modelCss:
/* Kit de formulário (profissional e reutilizável) */

:root {
  --border: rgba(17, 24, 39, 0.12);
  --accent: #60a5fa;
  --danger: #ef4444;
  --success: #22c55e;
}

.form {
  display: grid;
  gap: 14px;
}

.field {
  display: grid;
  gap: 6px;
}

.label {
  font-size: 0.875rem;
}

.input {
  width: 100%;
  padding: 10px 12px;
  border: 1px solid var(--border);
  border-radius: 12px;
  background: transparent;
}

.input:focus-visible {
  outline: 3px solid var(--accent);
  outline-offset: 2px;
  border-color: rgba(96, 165, 250, 0.6);
}

.input-error {
  border-color: var(--danger);
}

.help {
  font-size: 0.875rem;
  opacity: 0.85;
}

.help-error {
  color: var(--danger);
}

.input-success {
  border-color: var(--success);
}

.help-success {
  color: var(--success);
}

.input:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

.input[readonly] {
  background: rgba(0, 0, 0, 0.04);
}

.textarea {
  min-height: 120px;
  resize: vertical;
}

.btn {
  padding: 10px 14px;
  border-radius: 12px;
}

.btn:focus-visible {
  outline: 3px solid var(--accent);
  outline-offset: 3px;
}
